mapper.select:
SELECT * FROM ( SELECT rownum rn, TB.* FROM ( SELECT /*selectMyStockList*/ A.SEQ ,A.CODE ,B.STOCKS_NAME ,A.QY ,A.GUBUN ,(SELECT CODE_NM FROM COMTCCMMNDETAILCODE WHERE USE_AT='Y' AND CODE_ID='STRE' AND CODE=A.GUBUN) AS GUBUN_NM ,A.DELNG_DE ,A.FEE ,A.TRFTAX ,A.INCMTAX ,A.UNIT_PRICE ,A.SELL_PRICE ,A.ACCOUNT ,(A.QY*A.UNIT_PRICE)-(A.FEE+A.TRFTAX+A.INCMTAX) AS TOTAL_PRICE ,A.RM ,TO_CHAR(A.REG_DATE,'YYYY-MM-DD') AS REG_DATE FROM STOCKS_TRANSACTION_INFO A, STOCKS_LIST B WHERE A.CODE = B.STOCKS_CODE(+)
AND A.GUBUN = #{searchBubun}
AND B.STOCKS_NAME LIKE '%'||#{keyword}||'%'
AND A.ACCOUNT LIKE '%'||#{keyword}||'%'
ORDER BY A.CODE , A.DELNG_DE DESC ) TB ) WHERE rn BETWEEN #{firstIndex} + 1 AND #{firstIndex} + #{recordCountPerPage}

SELECT * FROM ( SELECT rownum rn, TB.* FROM ( SELECT /*selectMyStockHistList*/ B.SEQ ,B.P_SEQ ,A.CODE ,C.STOCKS_NAME ,B.QY ,B.GUBUN ,(SELECT CODE_NM FROM COMTCCMMNDETAILCODE WHERE USE_AT='Y' AND CODE_ID='STRE' AND CODE=B.GUBUN) AS GUBUN_NM ,B.DELNG_DE ,B.UNIT_PRICE ,(B.QY * B.UNIT_PRICE) AS TOTAL_PRICE ,B.RM ,TO_CHAR(B.UPD_DATE,'YYYY-MM-DD') AS UPD_DATE ,TO_CHAR(B.REG_DATE,'YYYY-MM-DD') AS REG_DATE FROM STOCKS_TRANSACTION_INFO A, STOCKS_TRANSACTION_HIST B, STOCKS_LIST C WHERE A.SEQ = B.P_SEQ AND A.CODE = C.STOCKS_CODE(+) AND B.P_SEQ = #{pSeq}
AND C.STOCKS_NAME LIKE '%'||#{keyword}||'%'
ORDER BY B.DELNG_DE DESC ) TB )
